type Person = { Name: string; Age: int }

let alice = { Name = "Alice"; Age = 30 }
let older = { alice with Age = 31 }   // copy-and-update

printfn "%b" (alice = { Name = "Alice"; Age = 30 })  // true (structural)

let divmod a b = (a / b, a % b)

let (q, r) = divmod 17 5
printfn "q=%d r=%d" q r    // q=3 r=2

let pair = (1, "one")
printfn "%d %s" (fst pair) (snd pair)

let fetch id = async {
    do! Async.Sleep 100
    return sprintf "item-%d" id
}

let results =
    [1; 2; 3]
    |> List.map fetch
    |> Async.Parallel
    |> Async.RunSynchronously

printfn "%A" results

let validateAge age =
    if age >= 0 then Ok age else Error "negative age"

let validateAdult age =
    if age >= 18 then Ok age else Error "must be adult"

let check age =
    validateAge age
    |> Result.bind validateAdult

printfn "%A" (check 20)   // Ok 20
printfn "%A" (check 5)    // Error "must be adult"

let factorial n =
    let rec loop acc i =
        if i <= 1 then acc
        else loop (acc * i) (i - 1)   // tail call
    loop 1 n

printfn "%d" (factorial 5)   // 120
